        staleSnapshot!.ChunkCoordinate,
        staleSnapshot.SubchunkIndex,
        staleSnapshot.Revision,
        staleSnapshot.BuildVersion,
        SubchunkMeshing.BuildVisibleFaces(staleSnapshot));

